head.b:skin:
/* VARIABLES */
:root { --header-bg: #001f3f; --accent: #ce0000; --bg: #f4f7f6; }

/* RESET */
body { margin:0; padding:0; font-family:'Vazir',sans-serif; background:var(--bg); color:#333; }
a { text-decoration:none; color:inherit; }
img { max-width:100%; height:auto; }

/* HEADER */
.site-header { background:var(--header-bg); color:#fff; padding:20px; text-align:center; }
.site-title { font-size:30px; font-weight:900; }

/* LAYOUT */
.container { max-width:1200px; margin:30px auto; display:grid; grid-template-columns:1fr 300px; gap:30px; padding:0 15px; }

/* BLOG WIDGET STYLES (THE IMPORTANT PART) */
.blog-posts { display:grid; grid-template-columns:repeat(2, 1fr); gap:20px; }

/* FIRST POST HERO */
.blog-posts .post-outer:first-child { grid-column:1 / -1; }
.blog-posts .post-outer:first-child .post { display:grid; grid-template-columns:1fr 1fr; background:#fff; border-radius:8px; overflow:hidden; min-height:350px; }

/* GRID ITEMS */
.post { background:#fff; border-radius:8px; overflow:hidden; padding:0; display:flex; flex-direction:column; box-shadow:0 2px 5px rgba(0,0,0,0.05); }
.post-body { padding:15px; }
.post-title { font-size:18px; font-weight:bold; margin-bottom:10px; }

/* RESPONSIVE */
@media(max-width:768px){ .container{grid-template-columns:1fr;} .blog-posts{grid-template-columns:1fr;} .blog-posts .post-outer:first-child .post{grid-template-columns:1fr;} }
